// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';

function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [woodBusinessFarm, setWoodBusinessFarm] = useState(null);
  const [woodActivities, setWoodActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const [woodActivityFormData, setWoodActivityFormData] = useState({
    speciesName: '', // Tên lâm sản (mặc định) - sẽ được điền từ dữ liệu cơ sở
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // Function to fetch wood business details and wood activity records
  const fetchWoodDetails = useCallback(async () => {
	  console.log("Fetching wood details for farmId:", farmId); // THÊM DÒNG NÀY
    console.log("Token:", token ? "Exist" : "Not Exist"); // THÊM DÒNG NÀY
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // 1. Lấy chi tiết CƠ SỞ KINH DOANH GỖ (sử dụng farmId)
      // Cổng API là 10000
      const resWoodBusinessFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setWoodBusinessFarm(resWoodBusinessFarm.data);

      // Lấy Tên lâm sản mặc định từ resWoodBusinessFarm.data.loaiDongVatRung
      // Đảm bảo loaiDongVatRung tồn tại và có ít nhất một phần tử
      if (resWoodBusinessFarm.data.loaiDongVatRung && resWoodBusinessFarm.data.loaiDongVatRung.length > 0) {
        setWoodActivityFormData(prev => ({
          ...prev,
          speciesName: resWoodBusinessFarm.data.loaiDongVatRung[0].tenLamSan // Lấy tenLamSan từ mục đầu tiên
        }));
      }

      // 2. Lấy các bản ghi hoạt động nhập xuất gỗ cho CƠ SỞ này (sử dụng farmId)
      // Cổng API là 10000
      const resWoodActivities = await axios.get(`http://localhost:10000/api/wood-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setWoodActivities(resWoodActivities.data);

    } catch (err) {
      console.error('Lỗi khi tải chi tiết cơ sở gỗ hoặc bản ghi hoạt động:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Không thể tải chi tiết cơ sở gỗ hoặc bản ghi hoạt động.');
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/woods');
      }
    } finally {
      setLoading(false);
    }
  }, [farmId, token, navigate]);

  useEffect(() => {
    console.log("WoodDetail.js: useEffect is running!");
    if (farmId && token) {
      fetchWoodDetails(); // Đã sửa tên hàm đúng
    } else if (!farmId) {
		console.error('farmId is missing!'); // THÊM DÒNG NÀY
      setError('Không có ID cơ sở gỗ để xem chi tiết.');
      setLoading(false);
    } else if (!token) {
	console.error('Token is missing!'); // THÊM DÒNG NÀY	
      setError('Bạn cần đăng nhập để xem chi tiết cơ sở gỗ.');
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate, fetchWoodDetails]); // Đã sửa tên hàm trong dependency array

  const handleWoodActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...woodActivityFormData };

    if (['speciesName', 'date', 'quantity', 'unit', 'type', 'reason', 'source', 'destination', 'verifiedBy'].includes(name)) {
      newFormData = {
        ...newFormData,
        [name]: name === 'quantity' ? parseInt(value, 10) || 0 : value,
      };
    }
    setWoodActivityFormData(newFormData);
  };

  const handleAddWoodActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      const dataToSend = {
        ...woodActivityFormData,
        farm: farmId, // Liên kết hoạt động với farmId của cơ sở
      };
      // Cổng API là 10000
      const res = await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Bản ghi hoạt động gỗ đã được thêm thành công!');
      setWoodActivities(prevActivities => [...prevActivities, res.data]);
      setWoodActivityFormData(prev => ({
        ...prev,
        date: '',
        quantity: 0,
        unit: '',
        type: '',
        reason: '',
        source: '',
        destination: '',
        verifiedBy: '',
      }));
    } catch (err) {
      console.error('Lỗi khi thêm bản ghi hoạt động gỗ:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Lỗi khi thêm bản ghi hoạt động gỗ.');
    }
  };

  const handleDeleteWoodActivity = async (activityId) => {
    const confirmed = window.confirm('Bạn có chắc chắn muốn xóa bản ghi này?');
    if (confirmed) {
      setMessage('');
      setError('');
      try {
        // Cổng API là 10000
        await axios.delete(`http://localhost:10000/api/wood-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('Bản ghi đã được xóa thành công.');
        setWoodActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Lỗi khi xóa bản ghi hoạt động gỗ:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Lỗi khi xóa bản ghi hoạt động gỗ.');
      }
    }
  };

  if (loading) {
    return <div className="form-container"><p>Đang tải dữ liệu...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lỗi: {error}</p>
        <button onClick={() => navigate('/admin/woods')}>Quay lại danh sách cơ sở gỗ</button>
      </div>
    );
  }

  if (!woodBusinessFarm) {
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>Không tìm thấy thông tin cơ sở kinh doanh gỗ.</p>
        <button onClick={() => navigate('/admin/woods')}>Quay lại danh sách cơ sở gỗ</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      <style>
        {`
        .form-section-wrapper {
          flex: 1;
          min-width: 300px;
          padding: 3px;
          box-sizing: border-box;
        }

        .form-section-row {
          display: flex;
          gap: 15px;
          margin-bottom: 3px;
          align-items: center;
        }

        .form-group input[type="number"],
        .form-group input[type="text"],
        .form-group input[type="date"],
        .form-group select {
          width: 100%;
          box-sizing: border-box;
          padding: 8px 10px;
        }

        .form-container h2 {
          margin-bottom: 5px;
        }

        .form-container h3 {
          margin-top: 8px;
          margin-bottom: 3px;
        }

        .form-group {
            margin-bottom: 5px;
        }

        .form-group label {
          margin-bottom: 3px;
        }

        .modern-form .form-grid:first-of-type {
            margin-top: 0;
            padding-top: 0;
        }

        .modern-form .form-grid .form-group:last-of-type {
            margin-bottom: 0;
        }
        .modern-form h4 {
            margin-top: 5px;
            margin-bottom: 3px;
        }

        .modern-form .form-grid {
            gap: 15px;
        }
        `}
      </style>

      <h2>👁️ Nhật ký hoạt động gỗ của cơ sở: {woodBusinessFarm.tenCoSo || 'N/A'}</h2>

      <div className="form-grid">
        <div className="detail-group">
          <strong>Tên cơ sở:</strong> <p>{woodBusinessFarm.tenCoSo || 'N/A'}</p>
        </div>
        <div className="detail-group">
          <strong>Địa chỉ cơ sở:</strong> <p>{woodBusinessFarm.diaChiCoSo || 'N/A'}</p>
        </div>
        <div className="form-group detail-group">
          <label>Tên lâm sản (mặc định):</label>
          <select
            name="speciesName"
            value={woodActivityFormData.speciesName}
            onChange={handleWoodActivityFormChange}
            required
          >
            <option value="">-- Chọn lâm sản --</option>
            {woodBusinessFarm.loaiDongVatRung && woodBusinessFarm.loaiDongVatRung.map((species, index) => (
              <option key={index} value={species.tenLamSan}>
                {species.tenLamSan}
              </option>
            ))}
          </select>
        </div>
      </div>

      <h3>Thêm bản ghi nhập/xuất gỗ mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddWoodActivity} className="modern-form">
        <div className="form-grid">
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input
              type="date"
              name="date"
              value={woodActivityFormData.date}
              onChange={handleWoodActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select
              name="type"
              value={woodActivityFormData.type}
              onChange={handleWoodActivityFormChange}
              required
            >
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>
          <div className="form-group">
            <label>Số lượng:</label>
            <input
              type="number"
              name="quantity"
              value={woodActivityFormData.quantity}
              onChange={handleWoodActivityFormChange}
              min="0"
              required
            />
          </div>
          <div className="form-group">
            <label>Đơn vị:</label>
            <input
              type="text"
              name="unit"
              value={woodActivityFormData.unit}
              onChange={handleWoodActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Lý do:</label>
            <input
              type="text"
              name="reason"
              value={woodActivityFormData.reason}
              onChange={handleWoodActivityFormChange}
            />
          </div>
          {woodActivityFormData.type === 'import' && (
            <div className="form-group">
              <label>Nguồn gốc:</label>
              <input
                type="text"
                name="source"
                value={woodActivityFormData.source}
                onChange={handleWoodActivityFormChange}
              />
            </div>
          )}
          {woodActivityFormData.type === 'export' && (
            <div className="form-group">
              <label>Nơi đến:</label>
              <input
                type="text"
                name="destination"
                value={woodActivityFormData.destination}
                onChange={handleWoodActivityFormChange}
              />
            </div>
          )}
          <div className="form-group">
            <label>Người xác nhận:</label>
            <input
              type="text"
              name="verifiedBy"
              value={woodActivityFormData.verifiedBy}
              onChange={handleWoodActivityFormChange}
            />
          </div>
        </div>

        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      <h3>Lịch sử nhập/xuất gỗ:</h3>
      <div className="activity-list-container">
        {woodActivities.length === 0 ? (
          <p>Chưa có bản ghi nhập/xuất gỗ nào cho cơ sở này.</p>
        ) : (
          <table className="activity-table">
            <thead>
              <tr>
                <th>STT</th>
                <th>Ngày</th>
                <th>Loài gỗ</th>
                <th>Loại giao dịch</th>
                <th>Số lượng</th>
                <th>Đơn vị</th>
                <th>Lý do</th>
                <th>Nguồn gốc</th>
                <th>Nơi đến</th>
                <th>Người xác nhận</th>
                {role === 'admin' && <th>Xóa</th>}
              </tr>
            </thead>
            <tbody>
              {woodActivities.map((activity, index) => {
                return (
                  <tr key={activity?._id || `temp-key-${Math.random()}`}>
                    <td>{index + 1}</td>
                    <td>{activity?.date ? new Date(activity.date).toLocaleDateString() : 'N/A'}</td>
                    <td>{activity?.speciesName ?? 'N/A'}</td>
                    <td>{activity?.type === 'import' ? 'Nhập' : (activity?.type === 'export' ? 'Xuất' : 'N/A')}</td>
                    <td>{activity?.quantity ?? 0}</td>
                    <td>{activity?.unit ?? 'N/A'}</td>
                    <td>{activity?.reason ?? 'N/A'}</td>
                    <td>{activity?.source ?? 'N/A'}</td>
                    <td>{activity?.destination ?? 'N/A'}</td>
                    <td>{activity?.verifiedBy ?? 'N/A'}</td>
                    {role === 'admin' && (
                      <td>
                        <button onClick={() => handleDeleteWoodActivity(activity._id)} className="delete-button">Xóa</button>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
      <div className="detail-actions">
        <button onClick={() => navigate('/admin/woods')} className="cancel-button">Quay lại danh sách cơ sở gỗ</button>
      </div>
    </div>
  );
}

export default WoodDetail;
